<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">run-parts:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> executing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/kernel/postinst.d/dkms</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 6.1.25-lkp-kernel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /boot/vmlinuz-6.1.25-lkp-kernel</span></span>
